/**
 * @summary Upload a background image
 */
export const getUploadBackgroundUrl = () => {
  return `/api/backgrounds`;
};

export const uploadBackground = async (
  uploadBackgroundBody: UploadBackgroundBody,
  options?: RequestInit,
): Promise<BackgroundImage> => {
  const formData = new FormData();
  if (uploadBackgroundBody.label !== undefined) {
    formData.append(`label`, uploadBackgroundBody.label);
  }
  formData.append(`file`, uploadBackgroundBody.file);
  if (uploadBackgroundBody.animationSpeed !== undefined) {
    formData.append(
      `animationSpeed`,
      uploadBackgroundBody.animationSpeed.toString(),
    );
  }

  return customFetch<BackgroundImage>(getUploadBackgroundUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

